public class BoundaryValueAnalysis {
  public static void main(String[] args) {
    int input = 10;
    if (input >= 0 && input <= 10) {
      System.out.println('Boundary 1');
    } else if (input > 10 && input <= 20) {
      System.out.println('Boundary 2');
    } else {
      System.out.println('Boundary 3');
